oxy_webhelp_navlinks = {"postgresql_protection_setup-d30753e33541":{"topics":[{"title":"Evaluate PostgreSQL SLA Domain options","shortdesc":"<p class=\"shortdesc\">Before creating an SLA Domain for a PostgreSQL workload, you can evaluate various         protection options that <span class=\"ph\">RSC<\/span> provides for PostgreSQL clusters.<\/p>","href":"postgresql\/postgresql_evaluate_sla_domain_options.html","attributes":{"data-id":"postgresql_evaluate_sla_domain_options"},"menu":{"hasChildren":false},"tocID":"postgresql_evaluate_sla_domain_options-d30753e33552","topics":[]},{"title":"Primary snapshot retention for PostgreSQL","shortdesc":"<p class=\"shortdesc\">Primary snapshot retention for PostgreSQL clusters provides data protection and         recovery by setting snapshot retention policies for various periods, including hourly,         daily, monthly, and yearly retention to meet compliance, business continuity, and disaster         recovery requirements.<\/p>","href":"postgresql\/postgresql_primary_snapshot_retention.html","attributes":{"data-id":"postgresql_primary_snapshot_retention"},"menu":{"hasChildren":false},"tocID":"postgresql_primary_snapshot_retention-d30753e33566","topics":[]},{"title":"WAL file retention on PostgreSQL host","shortdesc":"<p class=\"shortdesc\">Write-Ahead Log (WAL) file retention enables you to retain local WAL files on a         PostgreSQL host for a specific duration after backup, providing faster access to local logs         directly on the host for local recovery requirements.<\/p>","href":"postgresql\/wal_file_retention_postgresql_host.html","attributes":{"data-id":"wal_file_retention_postgresql_host"},"menu":{"hasChildren":false},"tocID":"wal_file_retention_postgresql_host-d30753e33577","topics":[]},{"title":"Retention lock for PostgreSQL SLA Domains","shortdesc":"<p class=\"shortdesc\">A retention lock on an <span class=\"ph\">RSC<\/span> SLA Domain is a security feature that         prevents premature deletion of PostgreSQL snapshots.<\/p>","href":"postgresql\/postgresql_retention_lock_sla_domain.html","attributes":{"data-id":"postgresql_retention_lock_sla_domain"},"menu":{"hasChildren":false},"tocID":"postgresql_retention_lock_sla_domain-d30753e33588","topics":[]},{"title":"Archiving for PostgreSQL snapshots","shortdesc":"<p class=\"shortdesc\">You can include an archival policy in an SLA Domain to archive PostgreSQL snapshots         to an archival location for long-term retention.<\/p>","href":"postgresql\/postgresql_archiving_snapshots.html","attributes":{"data-id":"postgresql_archiving_snapshots"},"menu":{"hasChildren":false},"tocID":"postgresql_archiving_snapshots-d30753e33602","next":"postgresql_archiving_snapshots-d30753e33602"},{"title":"Multiple archival locations for PostgreSQL","shortdesc":"<p class=\"shortdesc\">You can configure multiple archival policies within a single SLA Domain to automate         the delivery of snapshots and log data to distinct cloud storage targets.<\/p>","href":"postgresql\/multiple_archival_locations_postgresql.html","attributes":{"data-id":"multiple_archival_locations_postgresql"},"menu":{"hasChildren":false},"tocID":"multiple_archival_locations_postgresql-d30753e33624","topics":[]},{"title":"Replication for PostgreSQL snapshots","shortdesc":"<p class=\"shortdesc\">You can use the SLA Domain replication policy to replicate PostgreSQL snapshots from         one Rubrik cluster to another for disaster recovery.<\/p>","href":"postgresql\/postgresql_replication.html","attributes":{"data-id":"postgresql_replication"},"menu":{"hasChildren":false},"tocID":"postgresql_replication-d30753e33635","next":"postgresql_replication-d30753e33635"}]}};